/* Resume download — embedded PDF, forces save reliably everywhere
   (GitHub Pages, offline file://, in-app browsers). The PDF bytes are
   embedded as base64 so no separate file fetch is needed. */
(function () {
  'use strict';
  var FILENAME = 'Love_Joy_Daquiado_Resume.pdf';
  var B64 = "";

  var _url = null;
  function pdfUrl() {
    if (_url) return _url;
    var bytes = atob(B64);
    var arr = new Uint8Array(bytes.length);
    for (var i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
    _url = URL.createObjectURL(new Blob([arr], { type: 'application/pdf' }));
    return _url;
  }

  function download(e) {
    if (e) e.preventDefault();
    var a = document.createElement('a');
    a.href = pdfUrl();
    a.download = FILENAME;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  }

  function wire() {
    var links = document.querySelectorAll('a[href$="resume.pdf"], a[data-resume]');
    for (var i = 0; i < links.length; i++) {
      links[i].setAttribute('download', FILENAME);
      links[i].addEventListener('click', download);
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', wire);
  } else {
    wire();
  }
})();
